  /(app-)?csrftoken=[A-Za-z0-9]{8,}/gi,
  /Bearer\s+[A-Za-z0-9._\-]{12,}/gi,
  new RegExp(SENSITIVE_KEY + "=[^;&\\s\"']{6,}", "gi"),
  new RegExp(SENSITIVE_KEY + "\"\\s*:\\s*\"[^\"]{6,}\"", "gi"),
  { g: /\b[A-Za-z0-9_\-]{32,}\b/g, skip: (m) => UUID.test(m) },
];
