function redactStr(s) {
  if (typeof s !== "string") return s;
  for (const p of SECRET_PATTERNS) {
    if (p instanceof RegExp) s = s.replace(p, "<REDACTED>");
    else s = s.replace(p.g, (m) => (p.skip(m) ? m : "<REDACTED>"));
